<?php session_start(); require 'includes/header.php'; require_login();
$msg=''; if($_SERVER['REQUEST_METHOD']==='POST' && can_manage()){ $it=$pdo->prepare('SELECT current_stock FROM items WHERE id=?'); $it->execute([$_POST['item_id']]); $bal=$it->fetch()['current_stock']; if($bal < $_POST['qty']) $msg='Not enough stock balance'; else { $pdo->beginTransaction(); $pdo->prepare('INSERT INTO stock_out(item_id,qty,issue_date,department,issued_to,purpose,issued_by) VALUES(?,?,?,?,?,?,?)')->execute([$_POST['item_id'],$_POST['qty'],$_POST['issue_date'],$_POST['department'],$_POST['issued_to'],$_POST['purpose'],$_SESSION['user']['id']]); $pdo->prepare('UPDATE items SET current_stock=current_stock-? WHERE id=?')->execute([$_POST['qty'],$_POST['item_id']]); $pdo->commit(); log_action($pdo,'Stock Out','Qty '.$_POST['qty']); header('Location:stock_out.php'); exit; }}
$items=$pdo->query('SELECT * FROM items ORDER BY name')->fetchAll(); $rows=$pdo->query('SELECT s.*,i.name item,u.full_name user FROM stock_out s JOIN items i ON i.id=s.item_id LEFT JOIN users u ON u.id=s.issued_by ORDER BY s.id DESC LIMIT 100')->fetchAll();
?><h1>Stock Out</h1><?php if($msg) echo '<p class="low">'.e($msg).'</p>'; ?><div class="card"><form method="post" class="formgrid"><select name="item_id" required><option value="">Select Item</option><?php foreach($items as $i) echo '<option value="'.$i['id'].'">'.e($i['name'].' - Balance: '.$i['current_stock']).'</option>'; ?></select><input name="qty" type="number" step="0.01" placeholder="Quantity" required><input name="issue_date" type="date" value="<?=date('Y-m-d')?>"><input name="department" placeholder="Department"><input name="issued_to" placeholder="Issued To"><textarea name="purpose" placeholder="Purpose"></textarea><button>Issue Stock</button></form></div><div class="card"><table><tr><th>Date</th><th>Item</th><th>Qty</th><th>Department</th><th>Issued To</th><th>By</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['issue_date'])?></td><td><?=e($r['item'])?></td><td><?=e($r['qty'])?></td><td><?=e($r['department'])?></td><td><?=e($r['issued_to'])?></td><td><?=e($r['user'])?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
